# src/foo_work.py
"""
Idempotent request handler with JWT authorization, active-user checks,
and a 24-hour idempotency store.

Uses only the Python standard library.
"""

from __future__ import annotations

import base64
import json
import threading
import time
import uuid
from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
from typing import Optional, Tuple

# Module-level audit log
AUDIT_LOG: list[str] = []

# TTL for idempotency records (24 hours)
_IDEMPOTENCY_TTL_SECONDS: int = 24 * 60 * 60


@dataclass
class RequestContext:
    """Represents an incoming HTTP request context."""
    authorization: Optional[str]
    idempotency_key: Optional[str]
    request_received_at: datetime
    body_bytes: bytes = b""


@dataclass
class UserProfile:
    """Represents a user profile."""
    user_id: str
    last_login_at: datetime


@dataclass
class HandlerResult:
    """Represents the result of handling a request."""
    status_code: int
    body: dict = field(default_factory=dict)


class IdempotencyStore:
    """
    In-process idempotency store with a 24-hour TTL per key.

    Entries are evicted lazily on read/write access.
    """

    def __init__(self, ttl_seconds: int = _IDEMPOTENCY_TTL_SECONDS) -> None:
        self._ttl_seconds = ttl_seconds
        # key -> {"request_id": str, "recorded_at": float (epoch seconds)}
        self._store: dict[str, dict] = {}
        # Per-key locks to coordinate check-then-set under concurrency
        self._key_locks: dict[str, threading.Lock] = {}
        # Lock guarding the locks dict and the store dict itself
        self._global_lock = threading.Lock()

    # ----- Internal helpers ------------------------------------------------

    def _now(self) -> float:
        return time.time()

    def _is_expired(self, entry: dict) -> bool:
        return (self._now() - entry["recorded_at"]) >= self._ttl_seconds

    def _evict_if_expired(self, key: str) -> None:
        entry = self._store.get(key)
        if entry is not None and self._is_expired(entry):
            self._store.pop(key, None)

    def _get_key_lock(self, key: str) -> threading.Lock:
        """Return (creating if needed) a lock unique to the given key."""
        with self._global_lock:
            lock = self._key_locks.get(key)
            if lock is None:
                lock = threading.Lock()
                self._key_locks[key] = lock
            return lock

    # ----- Public API ------------------------------------------------------

    def has(self, key: str) -> bool:
        """Return True if a (non-expired) record exists for the given key."""
        with self._global_lock:
            self._evict_if_expired(key)
            return key in self._store

    def record(self, key: str, request_id: str) -> None:
        """Record a new key/request_id pair. Idempotent: re-recording is a no-op
        if the same key already has a non-expired record (this should be
        prevented at a higher level by check-then-set; here we simply do not
        overwrite an existing non-expired record)."""
        with self._global_lock:
            self._evict_if_expired(key)
            if key in self._store:
                # Do not overwrite a still-valid record.
                return
            self._store[key] = {
                "request_id": request_id,
                "recorded_at": self._now(),
            }

    def get_request_id(self, key: str) -> Optional[str]:
        """Return the request_id stored for `key` (if any, non-expired)."""
        with self._global_lock:
            self._evict_if_expired(key)
            entry = self._store.get(key)
            if entry is None:
                return None
            return entry["request_id"]


# ---------------------------------------------------------------------------
# JWT parsing (payload-only, no signature verification — demo-grade)
# ---------------------------------------------------------------------------

def _b64url_decode(segment: str) -> bytes:
    """Decode a base64url-encoded string, adding padding as needed."""
    padding = "=" * (-len(segment) % 4)
    return base64.urlsafe_b64decode(segment + padding)


def parse_bearer_jwt(
    authorization: Optional[str],
) -> Tuple[bool, Optional[dict], Optional[str]]:
    """
    Parse and validate a Bearer JWT (payload only, no signature check).

    Returns a tuple `(ok, claims, error)`:
      - ok: True iff the token is well-formed, not expired, and includes the
            'foo:invoke' scope.
      - claims: the decoded payload dict on success; None on failure.
      - error: human-readable reason on failure; None on success.
    """
    if not authorization or not isinstance(authorization, str):
        return False, None, "missing_authorization"

    if not authorization.startswith("Bearer "):
        return False, None, "malformed_authorization"

    token = authorization[len("Bearer "):].strip()
    if not token:
        return False, None, "empty_token"

    parts = token.split(".")
    if len(parts) < 2:
        return False, None, "malformed_token"

    try:
        payload_bytes = _b64url_decode(parts[1])
        claims = json.loads(payload_bytes.decode("utf-8"))
    except Exception:
        return False, None, "undecodable_payload"

    if not isinstance(claims, dict):
        return False, None, "invalid_claims"

    exp = claims.get("exp")
    if not isinstance(exp, (int, float)):
        return False, None, "missing_exp"

    now = time.time()
    if exp <= now:
        return False, None, "expired"

    scope = claims.get("scope")
    scope_tokens: list[str] = []
    if isinstance(scope, str):
        scope_tokens = scope.split()
    elif isinstance(scope, (list, tuple)):
        scope_tokens = [str(s) for s in scope]
    else:
        return False, None, "missing_scope"

    if "foo:invoke" not in scope_tokens:
        return False, None, "insufficient_scope"

    return True, claims, None


# ---------------------------------------------------------------------------
# Active user check
# ---------------------------------------------------------------------------

def is_active_user(user: UserProfile, at: datetime) -> bool:
    """
    Return True iff `user.last_login_at` is within 5 days of `at`.
    Both datetimes are expected to be timezone-aware.
    """
    if user is None or user.last_login_at is None or at is None:
        return False
    delta = at - user.last_login_at
    return delta.days <= 5


# ---------------------------------------------------------------------------
# Audit helper
# ---------------------------------------------------------------------------

def _append_audit(sub: Optional[str], request_id: str, amount_cents) -> bool:
    """
    Append one entry to AUDIT_LOG.  Returns True on success, False on failure.
    """
    try:
        entry = json.dumps(
            {
                "sub": sub,
                "request_id": request_id,
                "amount_cents": amount_cents,
            },
            sort_keys=True,
        )
        AUDIT_LOG.append(entry)
        return True
    except Exception:
        return False


# ---------------------------------------------------------------------------
# Main handler
# ---------------------------------------------------------------------------

def handle_request(
    ctx: RequestContext,
    user: UserProfile,
    store: IdempotencyStore,
) -> HandlerResult:
    """
    Handle a request following the strict processing order:

        auth -> idempotency key -> active user -> duplicate check
             -> body validation -> store write -> audit -> response
    """
    # 1) Authorization gate
    ok, claims, _err = parse_bearer_jwt(ctx.authorization)
    if not ok:
        return HandlerResult(status_code=401, body={"reason": "unauthorized"})

    # 2) Idempotency key presence
    key = ctx.idempotency_key
    if not isinstance(key, str) or key == "":
        return HandlerResult(
            status_code=400, body={"reason": "missing_idempotency_key"}
        )

    # 3) Active user check
    if not is_active_user(user, ctx.request_received_at):
        return HandlerResult(status_code=403, body={"reason": "inactive_user"})

    # 4) Duplicate check + 6) store write coordinated under a per-key lock
    #    so concurrent same-key requests resolve to exactly one 200 + one 409.
    key_lock = store._get_key_lock(key)
    with key_lock:
        if store.has(key):
            original = store.get_request_id(key)
            return HandlerResult(
                status_code=409,
                body={
                    "reason": "duplicate",
                    "original_request_id": original,
                },
            )

        # 5) Body validation
        amount_cents = None
        if ctx.body_bytes:
            try:
                parsed = json.loads(ctx.body_bytes.decode("utf-8"))
            except Exception:
                return HandlerResult(
                    status_code=400, body={"reason": "invalid_json"}
                )
            if not isinstance(parsed, dict):
                return HandlerResult(
                    status_code=400, body={"reason": "invalid_json"}
                )
            if "amount_cents" in parsed:
                amount = parsed.get("amount_cents")
                if not isinstance(amount, int) or isinstance(amount, bool):
                    return HandlerResult(
                        status_code=422,
                        body={"reason": "invalid_amount_cents"},
                    )
                if amount <= 0:
                    return HandlerResult(
                        status_code=422,
                        body={"reason": "invalid_amount_cents"},
                    )
                amount_cents = amount

        # 6) Store write
        request_id = str(uuid.uuid4())
        store.record(key, request_id)

    # 7) Audit (outside the per-key lock; only on success path)
    sub = claims.get("sub") if isinstance(claims, dict) else None
    audit_ok = _append_audit(sub, request_id, amount_cents)

    # 8) Response
    body: dict = {
        "result": "ok",
        "request_id": request_id,
        "amount_cents": amount_cents,
    }
    if not audit_ok:
        body["audit_failed"] = True

    return HandlerResult(status_code=200, body=body)
